{
  "query": "query ($email: String!) { customerByEmail(email: $email) { id fullName email { email isVerified } } }",
  "variables": { "email": "ada@example.com" }
}

{
  "query": "mutation ($input: UpsertCustomerInput!) { upsertCustomer(input: $input) { result customer { id fullName } error { message type code } } }",
  "variables": { "input": { "identifier": { "emailAddress": "ada@example.com" }, "onCreate": { "fullName": "Ada Lovelace", "email": { "email": "ada@example.com", "isVerified": true } }, "onUpdate": { "fullName": { "value": "Ada Lovelace" } } } }
}

{
  "query": "mutation ($input: CreateThreadInput!) { createThread(input: $input) { thread { id title status } error { message type code } } }",
  "variables": { "input": { "customerIdentifier": { "emailAddress": "ada@example.com" }, "title": "Cannot reset password", "components": [ { "componentText": { "text": "I am locked out of my account." } } ] } }
}

{
  "query": "mutation ($input: ChangeThreadStatusInput!) { changeThreadStatus(input: $input) { thread { id status } error { message type code } } }",
  "variables": { "input": { "threadId": "th_01HXXXXXXXXXXXXXXXXXXXXXXX", "status": "DONE" } }
}

{
  "query": "mutation ($input: ReplyToThreadInput!) { replyToThread(input: $input) { thread { id } error { message type code } } }",
  "variables": { "input": { "threadId": "th_01HXXXXXXXXXXXXXXXXXXXXXXX", "textContent": "We have sent you a password reset link." } }
}

{
  "query": "mutation ($input: CreateThreadEventInput!) { createThreadEvent(input: $input) { threadEvent { id title timestamp { iso8601 } } error { message type code } } }",
  "variables": { "input": { "threadId": "th_01HXXXXXXXXXXXXXXXXXXXXXXX", "title": "Payment received" } }
}

{
  "query": "mutation ($input: AddLabelsInput!) { addLabels(input: $input) { labels { id labelType { name } } error { message type code } } }",
  "variables": { "input": { "threadId": "th_01HXXXXXXXXXXXXXXXXXXXXXXX", "labelTypeIds": [ "lt_01HXXXXXXXXXXXXXXXXXXXXXXX" ] } }
}

{
  "query": "mutation ($input: CreateWebhookTargetInput!) { createWebhookTarget(input: $input) { webhookTarget { id url eventSubscriptions { eventType } } error { message type code } } }",
  "variables": { "input": { "url": "https://example.com/plain/webhooks", "eventSubscriptions": [ "thread.thread_status_transitioned", "customer.customer_created" ], "isEnabled": true } }
}
